import React, { useState, useEffect } from 'react';

const Slider = () => {
  const sliderData = [
    {
      title: "Fast Food Restaurant",
      description: "Doloremque, itaque aperiam facilis rerum, commodi, temporibus sapiente ad mollitia laborum quam quisquam esse error unde.",
      image: "/image/hero-bg.jpg" // Slide 1 Image
    },
    {
      title: "Delicious Pizza",
      description: "Veniam debitis quaerat officiis quasi cupiditate quo, nihil gubergren, eos natus lead architecto.",
      image: "/image/pizza-slide.png" // Replace with your 2nd image
    },
    {
      title: "Tasty Pasta",
      description: "Explicabo esse amet tempora quibusdam laudantium, ratione eaque omnis id delectus ducimus.",
      image: "/image/pasta-slide.png" // Replace with your 3rd image
    }
  ];

  const [current, setCurrent] = useState(0);

  // Auto-move slider every 5 seconds
  useEffect(() => {
    const next = (current + 1) % sliderData.length;
    const id = setTimeout(() => setCurrent(next), 5000);
    return () => clearTimeout(id);
  }, [current]);

  return (
    <section className="slider_section">
      <div className="container">
        <div className="row">
          <div className="detail-box">
            <h1>{sliderData[current].title}</h1>
            <p>
              {sliderData[current].description}
            </p>
            <div className="btn-box">
              <a href="" className="btn1">Order Now</a>
            </div>
          </div>
        </div>

        <div className="slider_indicators">
          {sliderData.map((_, index) => (
            <span key={index} className={`dot ${index === current ? 'active-dot' : ''}`}></span>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Slider;
